        alignItems: 'center',
        gap: '6px',
        backdropFilter: 'blur(8px)',
        transition: 'all 0.15s ease',
        whiteSpace: 'nowrap'
      }}
    >
      {icon}
      <span className="btn-label">{label}</span>
    </button>
  );

  return (
    <div style={{ width: '100%', height: '100vh', background: '#0a0a0a', position: 'relative', overflow: 'hidden' }}>
